#!/usr/bin/env sage
"""
Generate a Lean file certifying the q-expansion of a level-1 LMFDB modular form
via the polynomial-in-(E₄, E₆) framework.

Usage:
    sage scripts/lmfdb_qexp_to_e4e6.sage <weight> [<output_path>]

Example:
    sage scripts/lmfdb_qexp_to_e4e6.sage 16 \
        LeanBridge/ForMathlib/QExpansion/LMFDB_1_16_a_a.lean

Currently supports level-1 weights k where dim S_k = 1 (k = 12, 16, 18, 20, 22, 26).
For these weights the unique normalized newform is labelled `1.k.a.a` in the LMFDB.
"""


# This file was *autogenerated* from the file scripts/lmfdb_qexp_to_e4e6.sage
from sage.all_cmdline import *   # import sage library

_sage_const_12 = Integer(12); _sage_const_1 = Integer(1); _sage_const_5 = Integer(5); _sage_const_0 = Integer(0); _sage_const_2 = Integer(2); _sage_const_4 = Integer(4); _sage_const_6 = Integer(6); _sage_const_3 = Integer(3)
import sys
import os


def newform_to_E4E6_poly(k, prec=None):
    """Express the unique normalized weight-k cusp form as a polynomial in E₄, E₆.
    Returns a list of (a, b, c) where the form = sum c · E₄^a · E₆^b."""
    sturm = k // _sage_const_12  + _sage_const_1 
    if prec is None:
        prec = sturm + _sage_const_5 

    M = ModularForms(_sage_const_1 , k)
    cusp = M.cuspidal_subspace()
    if cusp.dimension() != _sage_const_1 :
        raise NotImplementedError(
            f"Weight {k}: cusp form space has dim {cusp.dimension()}, expected 1"
        )

    f = cusp.newforms('a')[_sage_const_0 ]
    f_qexp = f.qexp(prec + _sage_const_2 )
    if f_qexp[_sage_const_1 ] != _sage_const_0 :
        f_qexp = f_qexp / QQ(f_qexp[_sage_const_1 ])

    E4 = eisenstein_series_qexp(_sage_const_4 , prec + _sage_const_2 , normalization='constant')
    E6 = eisenstein_series_qexp(_sage_const_6 , prec + _sage_const_2 , normalization='constant')

    basis_pairs = [(a, b)
                   for a in range(k // _sage_const_4  + _sage_const_1 )
                   for b in range(k // _sage_const_6  + _sage_const_1 )
                   if _sage_const_4  * a + _sage_const_6  * b == k]
    n_basis = len(basis_pairs)
    basis_qexps = [E4 ** a * E6 ** b for (a, b) in basis_pairs]

    A = matrix(QQ, n_basis, n_basis,
               [[QQ(basis_qexps[j][i]) for j in range(n_basis)]
                for i in range(n_basis)])
    b_vec = vector(QQ, [QQ(f_qexp[i]) for i in range(n_basis)])

    coeffs = A.solve_right(b_vec)
    return [(int(a), int(b), c)
            for (a, b), c in zip(basis_pairs, coeffs) if c != _sage_const_0 ]


def first_lmfdb_qexp(k, n_coeffs):
    """Return the first n_coeffs of the unique normalized weight-k cusp form,
    as integers (these match what the LMFDB lists)."""
    M = ModularForms(_sage_const_1 , k)
    f = M.cuspidal_subspace().newforms('a')[_sage_const_0 ]
    f_qexp = f.qexp(n_coeffs + _sage_const_2 )
    if f_qexp[_sage_const_1 ] != _sage_const_0 :
        f_qexp = f_qexp / QQ(f_qexp[_sage_const_1 ])
    return [int(f_qexp[i]) for i in range(n_coeffs)]


def fmt_rat(c):
    """Format a rational as Lean syntax."""
    n = c.numerator()
    d = c.denominator()
    if d == _sage_const_1 :
        if n >= _sage_const_0 :
            return f"{n}"
        else:
            return f"({n})"
    if n >= _sage_const_0 :
        return f"({n} / {d})"
    else:
        return f"(-({-n} / {d}))"


def emit_lean(weight, poly, qexp_coeffs):
    """Generate the Lean file as a string."""
    label = f"1_{weight}_a_a"
    sturm = weight // _sage_const_12  + _sage_const_1 

    # Polynomial string: [(a, b, c), ...]
    poly_str = ", ".join(f"({a}, {b}, {fmt_rat(c)})" for (a, b, c) in poly)

    # Form definition: c1 • mkMonomForm a1 b1 weight (by decide) + c2 • ...
    form_terms = []
    for (a, b, c) in poly:
        form_terms.append(
            f"({fmt_rat(c)} : ℂ) • mkMonomForm {a} {b} {weight} (by decide)"
        )
    form_def = "\n  + ".join(["  " + t for t in form_terms]).lstrip()
    if not form_def:
        form_def = "0"

    # Bridge proof: rw chain
    n_monoms = len(poly)
    coe_smul_rws = ", ".join(["ModularForm.IsGLPos.coe_smul"] * n_monoms)
    qexp_smul_rws = ", ".join([
        "ModularForm.qExpansion_smul one_pos one_mem_strictPeriods_SL"
    ] * n_monoms)
    qexp_mon_rws = ", ".join(["qExpansion_mkMonomForm"] * n_monoms)

    # The number of `coe_add` and `qExpansion_add` rewrites needed depends on
    # tree shape: for n monomials, we have (n-1) addition nodes.
    n_adds = max(_sage_const_0 , n_monoms - _sage_const_1 )
    coe_add_rws = ", ".join(["ModularForm.coe_add"] * n_adds) if n_adds else ""
    qexp_add_rws = ", ".join([
        "ModularForm.qExpansion_add one_pos one_mem_strictPeriods_SL"
    ] * n_adds) if n_adds else ""

    rw_pieces = []
    if coe_add_rws:
        rw_pieces.append(coe_add_rws)
    if qexp_add_rws:
        rw_pieces.append(qexp_add_rws)
    rw_pieces += [coe_smul_rws, qexp_smul_rws, qexp_mon_rws]
    rw_chain = ",\n    ".join(rw_pieces)

    # Sturm-bound certificate examples
    sturm_examples = []
    for n in range(sturm):
        v = qexp_coeffs[n]
        v_str = f"({v})" if v < _sage_const_0  else f"{v}"
        sturm_examples.append(f"""example : (PowerSeries.coeff (R := ℂ) {n})
    (qExpansion 1 (lmfdb_{label} : ℍ → ℂ)) = {v} := by
  qexp_certify lmfdb_{label}_qExpansion_coeff lmfdb_{label}_polyData {sturm} {n} {v_str}""")
    sturm_examples_str = "\n\n".join(sturm_examples)

    return f"""import LeanBridge.ForMathlib.QExpansion.Generic
import LeanBridge.ForMathlib.QExpansion.Examples  -- for `qexp_certify` macro

/-!
# LMFDB level-1 modular form `1.{weight}.a.a`

The unique normalized cusp form of weight {weight}.

Polynomial in `(E₄, E₆)`, computed by Sage:
  `{' + '.join(f"{fmt_rat(c)} · E₄^{a} · E₆^{b}" for (a, b, c) in poly)}`

Sturm bound for weight {weight}: `⌊{weight}/12⌋ + 1 = {sturm}`. Verifying agreement on the
first {sturm} q-coefficients with the LMFDB-published expansion would, by Sturm + injectivity
of `evalE₄E₆`, identify this form as THE LMFDB form `1.{weight}.a.a`.

This file was generated by `scripts/lmfdb_qexp_to_e4e6.sage`.
-/

namespace LeanBridge.QExpansion

open ModularForm EisensteinSeries PowerSeries UpperHalfPlane
open scoped MatrixGroups

/-- Polynomial encoding of `1.{weight}.a.a` in `(E₄, E₆)`. -/
def lmfdb_{label}_polyData : List (ℕ × ℕ × ℚ) :=
  [{poly_str}]

/-- The level-1 modular form `1.{weight}.a.a`, defined as the polynomial in `E₄, E₆`. -/
noncomputable def lmfdb_{label} : ModularForm 𝒮ℒ {weight} :=
  {form_def}

lemma lmfdb_{label}_qExpansion_eq_evalEisPS :
    qExpansion 1 (lmfdb_{label} : ℍ → ℂ) = evalEisPS lmfdb_{label}_polyData := by
  unfold lmfdb_{label}
  rw [{rw_chain}]
  unfold evalEisPS lmfdb_{label}_polyData monomialEisPS
  simp only [List.foldr_cons, List.foldr_nil, add_zero]
  push_cast
  module

theorem lmfdb_{label}_qExpansion_coeff (N n : ℕ) (hn : n < N) :
    (PowerSeries.coeff (R := ℂ) n) (qExpansion 1 (lmfdb_{label} : ℍ → ℂ))
      = ((evalEisList lmfdb_{label}_polyData N).getD n 0 : ℚ) :=
  qexp_coeff_via_E4E6 lmfdb_{label}_polyData _
    lmfdb_{label}_qExpansion_eq_evalEisPS N n hn

/-! ## Sturm-bound certificates

Sturm bound for weight {weight} is {sturm}. The first {sturm} q-coefficients of `1.{weight}.a.a`
are `{qexp_coeffs[:sturm]}`. -/

{sturm_examples_str}

/- By the Sturm bound (and injectivity of `evalE₄E₆` from PR #38813), `lmfdb_{label}`
above equals the LMFDB form labelled `1.{weight}.a.a`. -/

end LeanBridge.QExpansion
"""


def main():
    if len(sys.argv) < _sage_const_2 :
        print(__doc__, file=sys.stderr)
        sys.exit(_sage_const_1 )
    weight = int(sys.argv[_sage_const_1 ])
    out_path = sys.argv[_sage_const_2 ] if len(sys.argv) >= _sage_const_3  else None

    poly = newform_to_E4E6_poly(weight)
    sturm = weight // _sage_const_12  + _sage_const_1 
    qexp_coeffs = first_lmfdb_qexp(weight, sturm + _sage_const_5 )

    lean_code = emit_lean(weight, poly, qexp_coeffs)

    if out_path:
        os.makedirs(os.path.dirname(os.path.abspath(out_path)), exist_ok=True)
        with open(out_path, 'w') as f:
            f.write(lean_code)
        print(f"Wrote {out_path}", file=sys.stderr)
    else:
        sys.stdout.write(lean_code)


main()

